'use client'

import { createContext, useContext, useEffect, useState } from 'react'
import { supabase } from '@/lib/supabase'
import type { User, Session } from '@supabase/supabase-js'
import { consumePendingProfileSeed, ensureProfileForUser } from '@/lib/profiles'

interface AuthContextType {
  user: User | null
  session: Session | null
  loading: boolean
}

const AuthContext = createContext<AuthContextType>({
  user: null,
  session: null,
  loading: true,
})

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<User | null>(null)
  const [session, setSession] = useState<Session | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    const resolveValidUser = async (session: Session | null) => {
      if (!session) return null

      const { data, error } = await supabase.auth.getUser()
      if (error || !data.user) {
        await supabase.auth.signOut()
        return null
      }

      return data.user
    }

    const ensureIdentity = async (sessionUser: User | null) => {
      if (!sessionUser) return

      const pendingSeed = consumePendingProfileSeed(sessionUser.id)
      try {
        await ensureProfileForUser(sessionUser, {
          username: pendingSeed?.username,
          fullName: pendingSeed?.fullName,
        })
      } catch (error) {
        const code = String((error as { code?: string })?.code || '')
        const message = String((error as { message?: string })?.message || '').toLowerCase()
        const expected =
          code === '42P01' ||
          code === '42501' ||
          message.includes('relation') ||
          message.includes('profiles') ||
          message.includes('permission denied')

        if (!expected) {
          console.error('auth.ensure-profile-error', error)
        }
      }
    }

    supabase.auth.getSession().then(async ({ data: { session } }) => {
      const validUser = await resolveValidUser(session)
      setSession(session)
      setUser(validUser)
      await ensureIdentity(validUser)
      setLoading(false)
    })

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange(async (_event, session) => {
      const validUser = await resolveValidUser(session)
      setSession(session)
      setUser(validUser)
      await ensureIdentity(validUser)
      setLoading(false)
    })

    return () => subscription.unsubscribe()
  }, [])

  return (
    <AuthContext.Provider value={{ user, session, loading }}>
      {children}
    </AuthContext.Provider>
  )
}

export const useAuth = () => {
  const context = useContext(AuthContext)
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider')
  }
  return context
}
